"use strict";
function pascalToKebabWithAbbr(name) {
  const kebab = name.replace(/([a-z0-9])([A-Z])/g, "$1-$2").replace(/([A-Z]+)([A-Z][a-z])/g, "$1-$2").toLowerCase();
  return [kebab];
}
function registerWithAliases(app, name, component) {
  for (const alias of pascalToKebabWithAbbr(name)) {
    app.component(alias, component);
  }
  app.component(name, component);
}
exports.registerWithAliases = registerWithAliases;
